void update_altitude() {
    uint16_t current_alt;
    uint16_t offset = get_sensor_offset();
    uint16_t new_alt = current_alt + offset;
    set_altitude(new_alt);
}

uint32_t calculate_true_altitude(void);
void process_radar(void) {
    uint16_t target_alt = calculate_true_altitude();
}

typedef void (*timer_cb_t)(void);
void my_callback(uint32_t id);
void register_timer(void) {
    timer_cb_t cb = (timer_cb_t)my_callback;
}

void handle_alert(uint8_t level) {
    switch (level) {
        case ALERT_LOW:
            print_warning();
        case ALERT_HIGH:
            trigger_alarm();
            break;
    }
}

void process_link_state(uint8_t state) {
    switch (state) {
        case STATE_INIT:
            init_link();
            break;
        case STATE_SYNC:
            sync_link();
            break;
    }
}

uint32_t calculate_track_prediction(uint32_t depth) {
    if (depth == 0U) {
        return 1U;
    }
    return depth * calculate_track_prediction(depth - 1U);
}
